    def _ensure_downloads(self) -> str:
        if self._download_dir is None:
            self._download_dir = tempfile.mkdtemp(prefix="rustwright-downloads-")
        Path(self._download_dir).mkdir(parents=True, exist_ok=True)
        if not self._downloads_enabled:
            _call(self._core.enable_downloads, self._download_dir, self._default_timeout)
            self._downloads_enabled = True
        return self._download_dir

    def _download_event_waiter(self) -> Any:
        download_dir = self._ensure_downloads()
        return self._core.download_event_waiter(download_dir)

    def _download_started_for_url(self, waiter: Any, url: str, *, timeout: float) -> bool:
        deadline = time.monotonic() + (timeout / 1000)
        while time.monotonic() < deadline:
            remaining = max(1.0, (deadline - time.monotonic()) * 1000)
            try:
                payload = json.loads(_call(waiter.wait, remaining))
            except TimeoutError:
                return False
            if (
                isinstance(payload, dict)
                and payload.get("url") == url
                and self._download_payload_belongs_to_page(payload)
            ):
                return True
        return False

    def _download_payload_belongs_to_page(self, payload: dict[str, Any]) -> bool:
        frame_id = payload.get("frame_id")
        if frame_id is None:
            return True
        frame_id = str(frame_id)
        if not frame_id:
            return True
        if self._main_frame._frame_id is None:
            self._main_frame._frame_id = self._main_frame_id_from_cdp()
        if self._main_frame._frame_id == frame_id:
            return True
        return self._cdp_frame_entry_for_id(frame_id) is not None

    def _wait_for_download_event(
        self,
        matcher: Any = None,
        *,
        timeout: Optional[float] = None,
        waiter: Any = None,
        reject_on_close: bool = True,
    ) -> Download:
        deadline, timeout_display = _event_deadline_for_target(self, timeout, method="Page.wait_for_event")
        waiter = waiter or self._download_event_waiter()
        owner = self if reject_on_close else None
        while True:
            remaining = _event_remaining_ms("download", timeout_display, deadline)
            try:
                payload = json.loads(_call(waiter.wait, _event_wait_step(remaining, owner)))
            except TimeoutError:
                try:
                    _handle_event_wait_timeout(owner, "download", timeout_display, deadline)
                except TimeoutError as exc:
                    raise exc from None
                continue
            if not isinstance(payload, dict) or not self._download_payload_belongs_to_page(payload):
                continue
            event = Download(self, payload, accepted=self._accept_downloads)
            if matcher is None or matcher(event):
                return event

