    def _maybe_start_transient_popup_adoption(self, expression: str) -> None:
        if "window.open" not in expression:
            return
        if self._event_handlers.get("popup"):
            return
        if getattr(self, "_active_page_cdp_event_contexts", 0) > 0:
            return
        existing = self._transient_popup_thread
        if existing is not None and existing.is_alive():
            return
        try:
            waiter = self._popup_event_waiter()
        except Error:
            return

        def adopt_popup() -> None:
            try:
                self._wait_for_popup_event(timeout=5_000.0, waiter=waiter, reject_on_close=False)
            except Exception:
                return

        thread = threading.Thread(target=adopt_popup, daemon=True, name="rustwright-evaluate-popup-adoption")
        self._transient_popup_thread = thread
        thread.start()

    def _wait_for_popup_event(
        self,
        matcher: Any = None,
        *,
        timeout: Optional[float] = None,
        waiter: Any = None,
        reject_on_close: bool = True,
    ) -> "Page":
        deadline, timeout_display = _event_deadline_for_target(self, timeout, method="Page.wait_for_event")
        waiter = waiter or self._popup_event_waiter()
        owner = self if reject_on_close else None
        while True:
            remaining = _event_remaining_ms("popup", timeout_display, deadline)
            try:
                popup = Page(_call(waiter.wait, _event_wait_step(remaining, owner)), context=self._context)
            except TimeoutError:
                try:
                    _handle_event_wait_timeout(owner, "popup", timeout_display, deadline)
                except TimeoutError as exc:
                    raise exc from None
                continue
            popup._opener = self
            if self._context is not None:
                self._context._adopt_popup(popup)
            if matcher is None or matcher(popup):
                return popup

