_ASSERTION_IMPL_PARAMETER_RENAMES = {
    "error_message": "errorMessage",
    "ignore_case": "ignoreCase",
    "title_or_reg_exp": "titleOrRegExp",
    "url_or_reg_exp": "urlOrRegExp",
    "use_inner_text": "useInnerText",
}
_ASSERTION_IMPL_REVERSE_PARAMETER_RENAMES = {
    public_name: internal_name
    for internal_name, public_name in _ASSERTION_IMPL_PARAMETER_RENAMES.items()
}


def _assertion_impl_signature(method_name: str) -> inspect.Signature:
    signature = inspect.signature(getattr(_Expectation, method_name))
    converted: list[inspect.Parameter] = []
    for parameter in signature.parameters.values():
        if parameter.name == "self":
            converted.append(parameter)
            continue
        public_name = _ASSERTION_IMPL_PARAMETER_RENAMES.get(parameter.name, parameter.name)
        converted.append(
            parameter.replace(
                name=public_name,
                kind=inspect.Parameter.POSITIONAL_OR_KEYWORD,
            )
        )

    if method_name in {"to_have_text", "not_to_have_text", "to_contain_text", "not_to_contain_text"}:
        order = {"expected": 0, "useInnerText": 1, "timeout": 2, "ignoreCase": 3}
        converted = [converted[0], *sorted(converted[1:], key=lambda parameter: order.get(parameter.name, 99))]
    elif method_name == "to_be_checked":
        order = {"timeout": 0, "checked": 1, "indeterminate": 2}
        converted = [converted[0], *sorted(converted[1:], key=lambda parameter: order.get(parameter.name, 99))]

    return signature.replace(parameters=converted)


def _call_assertion_impl_method(target: Any, method_name: str, args: tuple[Any, ...], kwargs: dict[str, Any]) -> Any:
    signature = inspect.signature(getattr(type(target), method_name))
    public_parameters = list(signature.parameters.values())[1:]
    if len(args) > len(public_parameters):
        raise TypeError(f"{method_name}() takes {len(public_parameters) + 1} positional arguments but more were given")

    translated = dict(kwargs)
    for index, value in enumerate(args):
        public_name = public_parameters[index].name
        internal_name = _ASSERTION_IMPL_REVERSE_PARAMETER_RENAMES.get(public_name, public_name)
        if public_name in translated or internal_name in translated:
            raise TypeError(f"{method_name}() got multiple values for argument '{public_name}'")
        translated[internal_name] = value
    for public_name, internal_name in _ASSERTION_IMPL_REVERSE_PARAMETER_RENAMES.items():
        if public_name in translated:
            if internal_name in translated:
                raise TypeError(f"{method_name}() got multiple values for argument '{public_name}'")
            translated[internal_name] = translated.pop(public_name)
    return getattr(target._expectation, method_name)(**translated)


def _make_assertion_impl_method(method_name: str) -> Callable[..., Any]:
    def method(self: Any, *args: Any, **kwargs: Any) -> Any:
        return _call_assertion_impl_method(self, method_name, args, kwargs)

    method.__name__ = method_name
    method.__signature__ = _assertion_impl_signature(method_name)  # type: ignore[attr-defined]
    return method


class _AssertionImplBase:
    def __init__(
        self,
        actual: Any,
        *,
        negate: bool = False,
        timeout: Optional[float] = None,
        message: Optional[str] = None,
    ):
        self._expectation = _Expectation(actual, negate=negate, timeout=timeout, message=message)


class _APIResponseAssertionsImpl(_AssertionImplBase):
    pass


class _LocatorAssertionsImpl(_AssertionImplBase):
    pass


class _PageAssertionsImpl(_AssertionImplBase):
    pass


_API_RESPONSE_ASSERTION_IMPL_METHODS = ["to_be_ok", "not_to_be_ok"]
_PAGE_ASSERTION_IMPL_METHODS = ["to_have_title", "to_have_url", "not_to_have_title", "not_to_have_url"]
_LOCATOR_ASSERTION_IMPL_METHODS = sorted(
    name
    for name in dir(_Expectation)
    if (name.startswith("to_") or name.startswith("not_to_"))
    and name not in set(_API_RESPONSE_ASSERTION_IMPL_METHODS + _PAGE_ASSERTION_IMPL_METHODS)
)

for _impl_cls, _method_names in (
    (_APIResponseAssertionsImpl, _API_RESPONSE_ASSERTION_IMPL_METHODS),
    (_LocatorAssertionsImpl, _LOCATOR_ASSERTION_IMPL_METHODS),
    (_PageAssertionsImpl, _PAGE_ASSERTION_IMPL_METHODS),
):
    for _method_name in _method_names:
        setattr(_impl_cls, _method_name, _make_assertion_impl_method(_method_name))
del _impl_cls, _method_names, _method_name


class _AssertionPublicMixin:
    def on(self, event: Any, f: Any) -> None:
        self._expectation.on(event, f)

    def once(self, event: Any, f: Any) -> None:
        self._expectation.once(event, f)

    def remove_listener(self, event: Any, f: Any) -> None:
        self._expectation.remove_listener(event, f)


def _make_assertion_public_method(method_name: str) -> Callable[..., Any]:
    def method(self: Any, *args: Any, **kwargs: Any) -> Any:
        return getattr(self._expectation, method_name)(*args, **kwargs)

    method.__name__ = method_name
    method.__signature__ = inspect.signature(getattr(_Expectation, method_name))  # type: ignore[attr-defined]
    return method


class APIResponseAssertions(_AssertionPublicMixin, _AssertionImplBase):
    pass


class LocatorAssertions(_AssertionPublicMixin, _AssertionImplBase):
    pass


class PageAssertions(_AssertionPublicMixin, _AssertionImplBase):
    pass


for _public_cls, _method_names in (
    (APIResponseAssertions, _API_RESPONSE_ASSERTION_IMPL_METHODS),
    (LocatorAssertions, _LOCATOR_ASSERTION_IMPL_METHODS),
    (PageAssertions, _PAGE_ASSERTION_IMPL_METHODS),
):
    for _method_name in _method_names:
        setattr(_public_cls, _method_name, _make_assertion_public_method(_method_name))
del _public_cls, _method_names, _method_name


class Expect:
    def __init__(self) -> None:
        self._timeout: Any = None

    def __call__(
        self,
        actual: Any,
        message: Optional[str] = None,
        *,
        timeout: Optional[float] = None,
    ) -> APIResponseAssertions | LocatorAssertions | PageAssertions:
        if not isinstance(actual, (Page, Locator, Response, APIResponse)):
            raise ValueError(f"Unsupported type: {type(actual)}")
        effective_timeout = timeout if timeout is not None else self._timeout
        if isinstance(actual, Page):
            return PageAssertions(actual, timeout=effective_timeout, message=message)
        if isinstance(actual, Locator):
            return LocatorAssertions(actual, timeout=effective_timeout, message=message)
        return APIResponseAssertions(actual, timeout=effective_timeout, message=message)

    def set_options(self, timeout: Any = _UNSET) -> None:
        if timeout is not _UNSET:
            self._timeout = timeout


